25→    @PostMapping("/register")
26→    public ResponseEntity<UserResponse> register(@Valid @RequestBody RegisterRequest request) {
27→        UserResponse response = authService.register(request);
28→        return ResponseEntity.status(HttpStatus.CREATED).body(response);
