40→        if (authentication == null || !(authentication.getPrincipal() instanceof Long)) {
41→            return ResponseEntity.status(HttpStatus.UNAUTHORIZED).build();
42→        }
43→        Long userId = (Long) authentication.getPrincipal();
44→        UserResponse response = authService.getCurrentUser(userId);
45→        return ResponseEntity.ok(response);
